import{_ as a,o as d,c as e,a2 as s}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"利多星金融数据产品专题","description":"","frontmatter":{},"headers":[],"relativePath":"projects/liduoxing/index.md","filePath":"projects/liduoxing/index.md"}'),n={name:"projects/liduoxing/index.md"};function r(i,t,l,o,p,h){return d(),e("div",null,[...t[0]||(t[0]=[s(`<h1 id="利多星金融数据产品专题" tabindex="-1">利多星金融数据产品专题 <a class="header-anchor" href="#利多星金融数据产品专题" aria-label="Permalink to &quot;利多星金融数据产品专题&quot;">​</a></h1><blockquote><p>利多星这一组项目，是我近期最贴近“数据产品经理 / 金融数据产品 / BI 与数据治理”方向的工作经历。它围绕 <span class="text-highlight">金融策略产品、用户行为、客户生命周期、客诉风控、渠道转化和经营看板</span> 展开，覆盖多个数据产品项目。</p></blockquote><div class="project-snapshot"><div><strong>2 个 BI 看板</strong><span>私享家产品看板（4 模块）+ 股民保护看板（3 模块），上线供业务方实际使用</span></div><div><strong>4 端数据接入</strong><span>APP、小程序、PC、企微聊天记录，替代原有手工报表</span></div><div><strong>多角色使用方</strong><span>业务负责人、产品运营主管、客服主管，从手工拉数到看板自助分析</span></div><div><strong>2 周 → 6 周交付</strong><span>股民保护半月上线；私享家因需数仓清洗，历时约 1.5 个月交付</span></div></div><h2 id="专题定位" tabindex="-1">专题定位 <a class="header-anchor" href="#专题定位" aria-label="Permalink to &quot;专题定位&quot;">​</a></h2><p>利多星项目的核心价值，是把金融业务中的复杂经营问题拆成可度量、可追踪、可复盘的数据链路。</p><p>业务侧关心的问题往往很具体：策略产品表现如何，客户是否活跃，服务是否覆盖到位，退款风险在哪里，投诉风险能不能提前识别，渠道来的资源能不能转化，哪些客户值得继续运营。要回答这些问题，不能只做页面，需要先把 <span class="text-highlight-warm">数据源、对象关系、指标口径、字段质量和业务流程</span> 梳理清楚。</p><p>这一组项目体现的能力集中在三件事：</p><ul><li>将业务问题拆成指标体系和看板结构。</li><li>将分散数据整理为可复用的宽表、标签和数据集。</li><li>将风险、服务、转化等流程做成可监控、可追踪、可复盘的产品框架。</li></ul><h2 id="项目目录" tabindex="-1">项目目录 <a class="header-anchor" href="#项目目录" aria-label="Permalink to &quot;项目目录&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>业务问题</th><th>数据产品价值</th></tr></thead><tbody><tr><td><a href="/projects/liduoxing/sixiangjia-bi.html">私享家 BI 数据看板</a></td><td>策略、客户、服务、订单和退款数据分散</td><td>建立策略收益、客户价值、产品分析、客服投顾服务和总览驾驶舱</td></tr><tr><td><a href="/projects/liduoxing/tracking-governance.html">数据埋点治理</a></td><td>多端行为数据字段不稳，影响 BI 和用户分析</td><td>建立埋点验收 SOP、质量分级、全量验数和宽表清洗规则</td></tr><tr><td><a href="/projects/liduoxing/ai-complaint-risk.html">AI 客诉与风控</a></td><td>客诉风险信号滞后，处理被动</td><td>将舆情、聊天语义、客户匹配和处置流程组织为风险识别闭环</td></tr><tr><td><a href="/projects/liduoxing/user-tags.html">用户分层与客户经营分析</a></td><td>客户生命周期分散在订单、退款、埋点和服务系统中</td><td>建立生命周期分层、ID 映射、客户宽表和运营标签框架</td></tr><tr><td><a href="/projects/liduoxing/woodpecker-bi.html">股民保护 BI 看板</a></td><td>公域资源、咨询、签约和维权流程依赖手工报表</td><td>建立从渠道曝光到签约转化的漏斗看板和业务驾驶舱</td></tr></tbody></table><h2 id="数据主线" tabindex="-1">数据主线 <a class="header-anchor" href="#数据主线" aria-label="Permalink to &quot;数据主线&quot;">​</a></h2><p>这组项目虽然场景不同，但底层方法是一致的。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>业务问题</span></span>
<span class="line"><span>  -&gt; 数据对象</span></span>
<span class="line"><span>  -&gt; 指标口径</span></span>
<span class="line"><span>  -&gt; 数据质量</span></span>
<span class="line"><span>  -&gt; 宽表 / 标签 / 看板</span></span>
<span class="line"><span>  -&gt; 业务复盘</span></span></code></pre></div><table tabindex="0"><thead><tr><th>数据对象</th><th>典型来源</th><th>作用</th></tr></thead><tbody><tr><td>用户行为</td><td>神策埋点、APP、小程序、PC、H5 页面</td><td>判断访问、点击、观看、互动和功能偏好</td></tr><tr><td>客户与订单</td><td>订单表、退款表、用户账户、服务周期</td><td>判断在期、退款、复购、客户净增和生命周期</td></tr><tr><td>策略与产品</td><td>策略组合、案例股、持仓、内容服务</td><td>判断策略收益、风险、产品价值和主推方向</td></tr><tr><td>服务过程</td><td>企微聊天、派工关系、客服投顾服务记录</td><td>判断服务覆盖、未互动客户、回复率和服务风险</td></tr><tr><td>风险线索</td><td>公域评论、投诉语义、客户反馈、历史外诉复盘</td><td>判断风险等级、触达优先级和处置路径</td></tr><tr><td>渠道资源</td><td>视频号、公众号、私域 H5、咨询登记、签约记录</td><td>判断渠道质量、进线效率和签约转化</td></tr></tbody></table><h2 id="我的角色" tabindex="-1">我的角色 <a class="header-anchor" href="#我的角色" aria-label="Permalink to &quot;我的角色&quot;">​</a></h2><p>在利多星项目中，我主要承担 <span class="text-highlight-blue">数据产品 / BI 产品 / 数据治理协同</span> 角色，需要在业务方、数据研发、产品开发、客服/投顾、管理层之间反复对齐口径。</p><table tabindex="0"><thead><tr><th>工作方向</th><th>我的职责</th></tr></thead><tbody><tr><td>业务理解</td><td>访谈业务负责人，理解策略产品、客户服务、客诉、渠道转化等真实场景</td></tr><tr><td>指标设计</td><td>将业务问题拆成核心指标、筛选维度、下钻路径和明细字段</td></tr><tr><td>数据治理</td><td>梳理埋点验收、字段质量、ID 映射、宽表清洗和数据可用性判断</td></tr><tr><td>看板设计</td><td>输出 BI 看板结构、PRD、字段口径、demo 原型和页面说明</td></tr><tr><td>风险产品化</td><td>将客诉、外诉、服务未覆盖等问题转成风险识别和流程闭环</td></tr><tr><td>协同落地</td><td>与数仓、开发和业务方确认数据来源、计算方式、异常口径和展示边界</td></tr></tbody></table><h2 id="展示边界" tabindex="-1">展示边界 <a class="header-anchor" href="#展示边界" aria-label="Permalink to &quot;展示边界&quot;">​</a></h2><p>金融业务项目有较强敏感性，因此公开作品集只展示 <span class="text-highlight">方法、结构、口径和脱敏后的结果表达</span>。</p><p>不公开展示：</p><ul><li>内部客户姓名、手机号、账号、聊天原文。</li><li>完整 SQL、数据库表明细、后台地址和内部账号。</li><li>经营金额、未脱敏截图、投诉个案和敏感监管细节。</li><li>可反推出业务规模、客户身份或商业机密的原始数据。</li></ul><p>后续截图部分建议优先使用脱敏后的流程图、看板结构图、字段口径表和局部指标框架，避免展示完整内部系统截图。</p>`,22)])])}const u=a(n,[["render",r]]);export{g as __pageData,u as default};
